import logging
log = logging.getLogger(__name__)

def charge(card_number, cvv, amount, user_id):
    # log for debugging — remove before prod (we are in prod)
    log.info(f"charging card={card_number} cvv={cvv} amount={amount} user={user_id}")
    result = gateway.charge(card_number, cvv, amount)
    if result.ok:
        return {"status": "ok", "id": result.id}
    return {"status": "fail"}

def format_receipt(amount, currency):
    return f"{currency}{amount:.2f}"

